var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"헉헉......!!","JPN":"はあはあ……！！","ENG":"Huff, huff...","TWN":"哈……哈……！！"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"제기랄...... 훈련병 시절 마치고 이렇게 고생해 보긴 처음이군......","JPN":"くそ……訓練兵の時以来、こんな疲れたのは初めてだ……","ENG":"Damn it... I haven't been this exhausted since I got out of training camp.","TWN":"該死……自從訓練兵時代結束後，我還是第一次這麼累……"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"진짜...... 형 하나 잘못 둔 죄로 이게 무슨 고생이람?","JPN":"まったく……兄貴のおかげで、とんだ災難だよ。","ENG":"Really, all this wouldn't have happened if that jerk wasn't my brother.","TWN":"真的是……因為哥哥犯下的錯，搞得我們都要受這種苦嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"듣고 있어?! 형!","JPN":"聞いてるか！？　兄貴！","ENG":"Are you listening to me, Ian?","TWN":"你在聽嗎？！哥！"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이 빚은 나중에 천국에서 톡톡히 받아낼 테니까 미리 적금이라도 들고 있으라고!!","JPN":"この貸しは、いずれ天国で倍返しにしてもらうからな！　しっかり準備しておけよ！！","ENG":"I'm going to make you pay when I see you in heaven, so you'd better start saving up!","TWN":"這筆債我之後會在天國跟你討回來的，你最好事先開始存點錢！"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"메이슨! 저기야! 저기 뉴 오하이오와 연결된 컴퓨터가 있어!","JPN":"メイソン！　あそこだ！　あそこにニューオハイオと繋がってるコンピューターがある！","ENG":"Mason, there! That's the computer connected with the New Ohio!","TWN":"梅森！那裡！和新俄亥俄連接的電腦就在那裡！"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"정말이야? 그럼 함선 내부로 들어가지 않아도 되겠네?","JPN":"本当か？　なら、船の中に入らなくて済むんだな？","ENG":"Really? Then we won't have to get inside the ship at all.","TWN":"真的嗎？那不用進入艦船裡面也行？"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잘 됐어! 작전 통제를 위한 외부 콘솔인가 보군!","JPN":"ツイてるな！　作戦統制のための外部コンソールか！","ENG":"This is good. It must be the external console for operation control.","TWN":"太好了！ 是為了指揮作戰而設置的外部控制台！"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이제 저기서 터미널을 열고 형이 준비한 백도어 키만 넣으면 돼!","JPN":"だったらそこでターミナルを開いて、兄貴が用意してくれたバックドアキーを入れりゃ一件落着だ！","ENG":"We just have to open the terminal and put in the key to the backdoor Ian planted.","TWN":"我們現在只要到那裡把終端打開，然後輸入我哥準備的後門密碼就可以了！"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아악!!","JPN":"きゃああ！！","ENG":"Eeeek!","TWN":"呀啊啊！！"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"또, 또 뭐가 오는 거죠?","JPN":"こ、今度は何ですか？","ENG":"W-what's coming at us this time?","TWN":"又、又來了什麼？"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이, 이젠 다 싫어...... 집에 보내 줘요...... 제발......","JPN":"も、もうイヤだよ……家に帰りたいよぅ……お願いだよぅ……","ENG":"I-I can't take it anymore... Just let me go home, please...","TWN":"我、我受夠了……送我回家吧……拜託……"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"이런 제길! 리플레이서 놈들이 잔뜩 몰려온다!","JPN":"ちくしょう！　リプレイサーどもがなだれ込んでくるぞ！","ENG":"Drat! The Replacer bastards are coming at us in swarms!","TWN":"該死的！有一大堆克隆集團的傢伙過來了！"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"얼마 못 버틸 거 같아! 뭐든 간에 빨리 하라고 메이슨!!","JPN":"長くは持たない！　何でもいいから急げよ、メイソン！！","ENG":"We won't be able to last too long! Mason! Whatever it is you're going to do, do it fast!","TWN":"撐不了多久了！不管是什麼快點做就對了，梅森！"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잠깐이면 돼!","JPN":"あと少しでいいんだ！","ENG":"One moment!","TWN":"只要一下就好！"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};